#include <stdio.h>

int main() {
    int T, x;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &x);
        if (x < 100) {
            printf("Easy\n");
        } else if (x < 200) {
            printf("Medium\n");
        } else {
            printf("Hard\n");
        }
    }
    return 0;
}

