code.Python3:
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        x = int(data[i])
        if x < 100:
            out.append('Easy')
        elif x < 200:
            out.append('Medium')
        else:
            out.append('Hard')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

